insert into public.content_items (id, category, level, tags, uk, us, notes, clues, traps) values
  ('lift-elevator', 'vocabulary', 1, ARRAY['building', 'everyday']::text[], '{"term":"lift","sentence":"Take the lift to the third floor.","audioUrl":null}'::jsonb, '{"term":"elevator","sentence":"Take the elevator to the third floor.","audioUrl":null}'::jsonb, null, ARRAY['''Lift'' is UK.', '''Elevator'' is US.']::text[], ARRAY['In the UK, ''elevator'' is understood but sounds American.']::text[]),
  ('flat-apartment', 'vocabulary', 1, ARRAY['housing', 'everyday']::text[], '{"term":"flat","sentence":"She lives in a one-bedroom flat near the river.","audioUrl":null}'::jsonb, '{"term":"apartment","sentence":"She lives in a one-bedroom apartment near the river.","audioUrl":null}'::jsonb, null, ARRAY['''Flat'' is UK.', '''Apartment'' is US.']::text[], ARRAY['In the UK, ''apartment'' suggests something larger or more upmarket.']::text[]),
  ('queue-line', 'vocabulary', 1, ARRAY['everyday']::text[], '{"term":"queue","sentence":"Join the queue and wait your turn.","audioUrl":null}'::jsonb, '{"term":"line","sentence":"Get in line and wait your turn.","audioUrl":null}'::jsonb, null, ARRAY['''Queue'' is UK.', '''Line'' (or ''in line'') is US.']::text[], ARRAY[]::text[]),
  ('petrol-gasoline', 'vocabulary', 2, ARRAY['transport']::text[], '{"term":"petrol","sentence":"The car needs more petrol before we reach Bristol.","audioUrl":null}'::jsonb, '{"term":"gasoline","sentence":"The car needs more gas before we reach Denver.","audioUrl":null}'::jsonb, null, ARRAY['''Petrol'' is UK.', '''Gasoline'' or ''gas'' is US.']::text[], ARRAY['''Gas'' in the UK often means natural gas, not fuel.']::text[]),
  ('boot-trunk', 'vocabulary', 2, ARRAY['transport', 'car']::text[], '{"term":"boot","sentence":"Put the shopping in the boot.","audioUrl":null}'::jsonb, '{"term":"trunk","sentence":"Put the groceries in the trunk.","audioUrl":null}'::jsonb, null, ARRAY['Rear car storage: ''boot'' (UK), ''trunk'' (US).']::text[], ARRAY[]::text[]),
  ('chips-fries', 'vocabulary', 1, ARRAY['food']::text[], '{"term":"chips","sentence":"Fish and chips, please.","audioUrl":null}'::jsonb, '{"term":"fries","sentence":"Fish and fries, please.","audioUrl":null}'::jsonb, null, ARRAY['UK ''chips'' are thick-cut, usually hot.', 'US ''fries'' are thinner and always hot.']::text[], ARRAY['In the US, ''chips'' means crisps.', 'In the UK, ''crisps'' are cold snacks in a bag.']::text[]),
  ('biscuit-cookie', 'vocabulary', 1, ARRAY['food']::text[], '{"term":"biscuit","sentence":"I''ll have a biscuit with my tea.","audioUrl":null}'::jsonb, '{"term":"cookie","sentence":"I''ll have a cookie with my coffee.","audioUrl":null}'::jsonb, null, ARRAY['UK ''biscuit'' = US ''cookie''.']::text[], ARRAY['A US ''biscuit'' is a soft bread roll, not a sweet treat.']::text[]),
  ('trousers-pants', 'vocabulary', 2, ARRAY['clothing']::text[], '{"term":"trousers","sentence":"He ironed his trousers for the interview.","audioUrl":null}'::jsonb, '{"term":"pants","sentence":"He ironed his pants for the interview.","audioUrl":null}'::jsonb, null, ARRAY['''Trousers'' is UK.', '''Pants'' is US.']::text[], ARRAY['In the UK, ''pants'' means underwear — mix this up at your peril.']::text[]),
  ('holiday-vacation', 'vocabulary', 1, ARRAY['travel']::text[], '{"term":"holiday","sentence":"We''re going on holiday to Spain next month.","audioUrl":null}'::jsonb, '{"term":"vacation","sentence":"We''re going on vacation to Spain next month.","audioUrl":null}'::jsonb, null, ARRAY['''Holiday'' is UK.', '''Vacation'' is US.']::text[], ARRAY['In the US, ''holiday'' specifically means a public holiday.']::text[]),
  ('autumn-fall', 'vocabulary', 1, ARRAY['seasons']::text[], '{"term":"autumn","sentence":"The leaves change in autumn.","audioUrl":null}'::jsonb, '{"term":"fall","sentence":"The leaves change in the fall.","audioUrl":null}'::jsonb, null, ARRAY['''Autumn'' is standard in UK.', '''Fall'' is more common in US, though ''autumn'' is also used.']::text[], ARRAY[]::text[]),
  ('pavement-sidewalk', 'vocabulary', 1, ARRAY['city']::text[], '{"term":"pavement","sentence":"Walk on the pavement, not the road.","audioUrl":null}'::jsonb, '{"term":"sidewalk","sentence":"Walk on the sidewalk, not the road.","audioUrl":null}'::jsonb, null, ARRAY['''Pavement'' is UK.', '''Sidewalk'' is US.']::text[], ARRAY['In the US, ''pavement'' can mean the road surface itself.']::text[]),
  ('underground-subway', 'vocabulary', 2, ARRAY['transport', 'city']::text[], '{"term":"underground","sentence":"Take the Underground to King''s Cross.","audioUrl":null}'::jsonb, '{"term":"subway","sentence":"Take the subway to Grand Central.","audioUrl":null}'::jsonb, null, ARRAY['Urban rail: ''Underground''/''Tube'' (UK), ''subway'' (US).']::text[], ARRAY['In the UK, a ''subway'' is a pedestrian underpass.']::text[]),
  ('colour-color', 'spelling', 1, ARRAY['suffix-our']::text[], '{"term":"colour","sentence":"What''s your favourite colour?","audioUrl":null}'::jsonb, '{"term":"color","sentence":"What''s your favorite color?","audioUrl":null}'::jsonb, null, ARRAY['UK keeps ''-our'' in many words (colour, favour, honour).', 'US drops the ''u'' (color, favor, honor).']::text[], ARRAY[]::text[]),
  ('centre-center', 'spelling', 1, ARRAY['suffix-re']::text[], '{"term":"centre","sentence":"Meet me at the town centre.","audioUrl":null}'::jsonb, '{"term":"center","sentence":"Meet me at the town center.","audioUrl":null}'::jsonb, null, ARRAY['UK uses ''-re'' (centre, theatre, metre).', 'US uses ''-er'' (center, theater, meter).']::text[], ARRAY[]::text[]),
  ('organise-organize', 'spelling', 2, ARRAY['suffix-ise']::text[], '{"term":"organise","sentence":"Let''s organise the files by date.","audioUrl":null}'::jsonb, '{"term":"organize","sentence":"Let''s organize the files by date.","audioUrl":null}'::jsonb, null, ARRAY['Many verbs end in ''-ise'' (UK) or ''-ize'' (US): organise, realise, recognise.']::text[], ARRAY['Oxford spelling is UK but uses ''-ize''. Most UK publishers prefer ''-ise''.']::text[]),
  ('analyse-analyze', 'spelling', 2, ARRAY['suffix-yse']::text[], '{"term":"analyse","sentence":"We need to analyse the results before Friday.","audioUrl":null}'::jsonb, '{"term":"analyze","sentence":"We need to analyze the results before Friday.","audioUrl":null}'::jsonb, null, ARRAY['''-yse'' (UK) vs ''-yze'' (US).', 'Also: catalyse/catalyze, paralyse/paralyze.']::text[], ARRAY[]::text[]),
  ('travelled-traveled', 'spelling', 2, ARRAY['double-l']::text[], '{"term":"travelled","sentence":"She travelled across Europe by train.","audioUrl":null}'::jsonb, '{"term":"traveled","sentence":"She traveled across Europe by train.","audioUrl":null}'::jsonb, null, ARRAY['UK doubles the ''l'' before -ed/-ing.', 'US keeps a single ''l''.']::text[], ARRAY['Applies to unstressed -el verbs: cancelled/canceled, modelled/modeled.']::text[]),
  ('catalogue-catalog', 'spelling', 2, ARRAY['suffix-ogue']::text[], '{"term":"catalogue","sentence":"Order from the autumn catalogue.","audioUrl":null}'::jsonb, '{"term":"catalog","sentence":"Order from the fall catalog.","audioUrl":null}'::jsonb, null, ARRAY['''-ogue'' (UK) vs ''-og'' (US): catalogue, dialogue, monologue.']::text[], ARRAY[]::text[]),
  ('grey-gray', 'spelling', 1, ARRAY['colours']::text[], '{"term":"grey","sentence":"The sky turned a dull grey.","audioUrl":null}'::jsonb, '{"term":"gray","sentence":"The sky turned a dull gray.","audioUrl":null}'::jsonb, null, ARRAY['''Grey'' is the UK spelling.', '''Gray'' is the US spelling.']::text[], ARRAY[]::text[]),
  ('tyre-tire', 'spelling', 2, ARRAY['car']::text[], '{"term":"tyre","sentence":"I need a new tyre before the trip.","audioUrl":null}'::jsonb, '{"term":"tire","sentence":"I need a new tire before the trip.","audioUrl":null}'::jsonb, null, ARRAY['For the rubber on a wheel: ''tyre'' (UK), ''tire'' (US).']::text[], ARRAY['''Tire'' meaning ''get tired'' is spelt the same in both.']::text[]),
  ('cheque-check', 'spelling', 2, ARRAY['finance']::text[], '{"term":"cheque","sentence":"He wrote a cheque for the deposit.","audioUrl":null}'::jsonb, '{"term":"check","sentence":"He wrote a check for the deposit.","audioUrl":null}'::jsonb, null, ARRAY['Payment slip: ''cheque'' (UK), ''check'' (US).']::text[], ARRAY['Only for the financial sense. ''Check the box'' is the same in both.']::text[]),
  ('aluminium-aluminum', 'spelling', 3, ARRAY['science']::text[], '{"term":"aluminium","sentence":"Wrap it in aluminium foil.","audioUrl":null}'::jsonb, '{"term":"aluminum","sentence":"Wrap it in aluminum foil.","audioUrl":null}'::jsonb, null, ARRAY['UK: five syllables (''al-yoo-MIN-i-um'').', 'US: four syllables (''a-LOO-mi-num'').']::text[], ARRAY[]::text[]),
  ('programme-program', 'spelling', 2, ARRAY['media']::text[], '{"term":"programme","sentence":"The programme starts at nine.","audioUrl":null}'::jsonb, '{"term":"program","sentence":"The program starts at nine.","audioUrl":null}'::jsonb, null, ARRAY['UK uses ''programme'' for events/broadcasts; ''program'' is kept for software.', 'US uses ''program'' for everything.']::text[], ARRAY[]::text[]),
  ('schedule-pronunciation', 'pronunciation', 2, ARRAY['common-words']::text[], '{"term":"schedule","sentence":"Let''s stick to the schedule.","audioUrl":null,"ipa":"/ˈʃɛd.juːl/"}'::jsonb, '{"term":"schedule","sentence":"Let''s stick to the schedule.","audioUrl":null,"ipa":"/ˈskɛdʒ.uːl/"}'::jsonb, null, ARRAY['UK starts with a ''sh'' sound (''SHED-jool'').', 'US starts with a ''sk'' sound (''SKED-jool'').']::text[], ARRAY[]::text[]),
  ('tomato-pronunciation', 'pronunciation', 2, ARRAY['food']::text[], '{"term":"tomato","sentence":"A fresh tomato, please.","audioUrl":null,"ipa":"/təˈmɑː.təʊ/"}'::jsonb, '{"term":"tomato","sentence":"A fresh tomato, please.","audioUrl":null,"ipa":"/təˈmeɪ.toʊ/"}'::jsonb, null, ARRAY['UK middle vowel: ''ah'' (''to-MAH-to'').', 'US middle vowel: ''ay'' (''to-MAY-to'').']::text[], ARRAY[]::text[]),
  ('privacy-pronunciation', 'pronunciation', 3, ARRAY['common-words']::text[], '{"term":"privacy","sentence":"I value my privacy.","audioUrl":null,"ipa":"/ˈprɪv.ə.si/"}'::jsonb, '{"term":"privacy","sentence":"I value my privacy.","audioUrl":null,"ipa":"/ˈpraɪ.və.si/"}'::jsonb, null, ARRAY['UK starts with ''PRI'' (short ''i'').', 'US starts with ''PRY'' (long ''i'').']::text[], ARRAY[]::text[]),
  ('rhotic-r', 'pronunciation', 3, ARRAY['accent']::text[], '{"term":"car","sentence":"The car is outside.","audioUrl":null,"ipa":"/kɑː/"}'::jsonb, '{"term":"car","sentence":"The car is outside.","audioUrl":null,"ipa":"/kɑːr/"}'::jsonb, null, ARRAY['Standard UK English is non-rhotic — the ''r'' at the end is dropped.', 'Standard US English is rhotic — the ''r'' is pronounced.']::text[], ARRAY['West-Country UK accents are rhotic too. New England US accents drop their r''s.']::text[]),
  ('at-the-weekend', 'grammar', 2, ARRAY['prepositions']::text[], '{"term":"at the weekend","sentence":"I''ll see you at the weekend.","audioUrl":null}'::jsonb, '{"term":"on the weekend","sentence":"I''ll see you on the weekend.","audioUrl":null}'::jsonb, null, ARRAY['UK uses ''at the weekend''.', 'US uses ''on the weekend''.']::text[], ARRAY[]::text[]),
  ('in-hospital', 'grammar', 2, ARRAY['articles']::text[], '{"term":"in hospital","sentence":"She''s been in hospital since Tuesday.","audioUrl":null}'::jsonb, '{"term":"in the hospital","sentence":"She''s been in the hospital since Tuesday.","audioUrl":null}'::jsonb, null, ARRAY['UK drops ''the'' before institutions (in hospital, at university).', 'US keeps it (in the hospital, in college).']::text[], ARRAY[]::text[]),
  ('have-got', 'grammar', 2, ARRAY['verbs']::text[], '{"term":"have got","sentence":"I''ve got a meeting at three.","audioUrl":null}'::jsonb, '{"term":"have","sentence":"I have a meeting at three.","audioUrl":null}'::jsonb, null, ARRAY['UK: ''have got'' is natural in present-day usage.', 'US: simple ''have'' is more common.']::text[], ARRAY['Both exist in both dialects; this is a frequency difference, not a right/wrong one.']::text[]),
  ('past-tense-learnt', 'grammar', 2, ARRAY['verbs', 'past-tense']::text[], '{"term":"learnt","sentence":"She learnt French in school.","audioUrl":null}'::jsonb, '{"term":"learned","sentence":"She learned French in school.","audioUrl":null}'::jsonb, null, ARRAY['UK allows both ''learnt'' and ''learned'' in the past tense.', 'US prefers ''learned''.']::text[], ARRAY['Same pattern for: burnt/burned, dreamt/dreamed, spelt/spelled.']::text[]),
  ('collective-plural', 'grammar', 3, ARRAY['agreement']::text[], '{"term":"the team are","sentence":"The team are playing well.","audioUrl":null}'::jsonb, '{"term":"the team is","sentence":"The team is playing well.","audioUrl":null}'::jsonb, null, ARRAY['UK often treats collective nouns as plural (the team are).', 'US treats them as singular (the team is).']::text[], ARRAY[]::text[]),
  ('past-participle-gotten', 'grammar', 2, ARRAY['verbs']::text[], '{"term":"have got","sentence":"The weather has got worse.","audioUrl":null}'::jsonb, '{"term":"have gotten","sentence":"The weather has gotten worse.","audioUrl":null}'::jsonb, null, ARRAY['UK: past participle is ''got''.', 'US: past participle is often ''gotten'', especially for ''become''/''obtain'' senses.']::text[], ARRAY[]::text[]),
  ('at-university', 'usage', 2, ARRAY['education']::text[], '{"term":"at university","sentence":"She''s at university in Edinburgh.","audioUrl":null}'::jsonb, '{"term":"in college","sentence":"She''s in college in Boston.","audioUrl":null}'::jsonb, null, ARRAY['UK ''at university'' covers the whole institution.', 'US ''in college'' typically covers undergraduate study.']::text[], ARRAY['In the US, ''university'' exists too but ''college'' is the default conversational term.']::text[]),
  ('first-floor', 'usage', 2, ARRAY['building']::text[], '{"term":"first floor","sentence":"Her office is on the first floor — one up from the entrance.","audioUrl":null}'::jsonb, '{"term":"second floor","sentence":"Her office is on the second floor — one up from the entrance.","audioUrl":null}'::jsonb, null, ARRAY['UK ground floor = US first floor.', 'UK first floor = US second floor.']::text[], ARRAY['This is a counting difference, not a word difference. Always confirm the floor by function.']::text[]),
  ('dates-format', 'usage', 1, ARRAY['dates']::text[], '{"term":"5 November 2025","sentence":"The event is on 5 November 2025.","audioUrl":null}'::jsonb, '{"term":"November 5, 2025","sentence":"The event is on November 5, 2025.","audioUrl":null}'::jsonb, null, ARRAY['UK: day-month-year.', 'US: month-day-year.']::text[], ARRAY[]::text[]),
  ('time-format', 'usage', 2, ARRAY['time']::text[], '{"term":"half seven","sentence":"Shall we meet at half seven?","audioUrl":null}'::jsonb, '{"term":"seven-thirty","sentence":"Shall we meet at seven-thirty?","audioUrl":null}'::jsonb, null, ARRAY['UK speakers often say ''half seven'' meaning 7:30.', 'US speakers say ''seven-thirty'' or ''half past seven''.']::text[], ARRAY['German uses ''half seven'' to mean 6:30 — don''t confuse the two.']::text[])
